import { useState, useEffect, useRef, useCallback } from 'react'
import { motion, AnimatePresence } from 'framer-motion'

import Sidebar from './components/Sidebar'
import Header from './components/Header'
import DashboardView from './components/DashboardView'
import AssistantView from './components/AssistantView'
import UpdatesView from './components/UpdatesView'
import CleanerView from './components/CleanerView'
import OptimizerView from './components/OptimizerView'
import TerminalView from './components/TerminalView'
import SettingsPage from './components/SettingsPage'
import ServiceView from './components/ServiceView'
import ProcessView from './components/ProcessView'
import NetworkView from './components/NetworkView'
import BootView from './components/BootView'
import DiskView from './components/DiskView'
import AuditView from './components/AuditView'
import PackagesView from './components/PackagesView'
import CommandPalette from './components/CommandPalette'
import ShortcutsOverlay from './components/ShortcutsOverlay'
import StatusBar from './components/StatusBar'
import LogView from './components/LogView'
import StartupView from './components/StartupView'
import ImageView from './components/ImageView'
import VideoView from './components/VideoView'
import GalleryView from './components/GalleryView'
import MemoryView from './components/MemoryView'
import OllamaModelsView from './components/OllamaModelsView'
import SnapshotView from './components/SnapshotView'
import HistoryView from './components/HistoryView'
import DockerView from './components/DockerView'
import HomeView from './components/HomeView'
import SandboxView from './components/SandboxView'
import AutomationsView from './components/AutomationsView'
import CronView from './components/CronView'
import SshView from './components/SshView'
import FirewallView from './components/FirewallView'
import BenchmarkView from './components/BenchmarkView'
import VaultView from './components/VaultView'
import EnvView from './components/EnvView'
import AppLauncherView from './components/AppLauncherView'
import HealthReportView from './components/HealthReportView'
import SchedulerView from './components/SchedulerView'
import DepGraph from './components/DepGraph'
import LogAnalysisView from './components/LogAnalysisView'
import DockerComposeBuilderView from './components/DockerComposeBuilderView'
import { useTheme } from './components/ThemeProvider'
import { navItems } from './components/Sidebar'
import { ALERT_THRESHOLDS_KEY, DEFAULT_THRESHOLDS, type AlertThresholds } from './components/SettingsPage'
import { notify } from './lib/notifications'

interface SystemStats {
  cpu?: {
    manufacturer?: string
    brand?: string
    speed?: number
    cores?: number
    load: number
  }
  memory?: {
    total: number
    free?: number
    used: number
    active?: number
  }
  network?: {
    rx_sec: number
    tx_sec?: number
    iface: string
  }
  storage?: {
    used: number
    size: number
    use: number
  }
  gpu?: {
    model: string
    utilizationGpu: number
    memoryUsed: number
    memoryTotal: number
    temperatureGpu: number
    powerDraw: number
    powerLimit: number
    fanSpeed: number
    clockCore: number
    utilizationMemory: number
  }
}

interface ActiveViewProps {
  onNavigate?: (tab: string) => void
  onExplore?: (name: string) => void
  initialPackage?: string | null
  onAnimate?: (url: string) => void
  i2vSource?: string | null
  onAskAI?: (tab: string) => void
  stats?: SystemStats | null
}

interface PackageDepTree {
  name: string
  version: string
  direct: string[]
  optional: string[]
  required: string[]
  depDetails: Record<string, string[]>
}

declare global {
  interface Window {
    electron: import('./types/electron').ElectronAPI & {
      comfyPurge?: () => Promise<{ success: boolean; error?: string }>
      packageGetTree?: (name: string) => Promise<PackageDepTree | null>
    }
  }
}

const VIEW_MAP: Record<string, React.ComponentType<ActiveViewProps>> = {
  dashboard: DashboardView,
  home: HomeView,
  assistant: AssistantView,
  updates: UpdatesView,
  sandbox: SandboxView,
  optimizer: OptimizerView,
  cleaner: CleanerView,
  packages: PackagesView,
  depgraph: DepGraphWrapper,
  processes: ProcessView,
  services: ServiceView,
  docker: DockerView,
  'compose-builder': DockerComposeBuilderView,
  network: NetworkView,
  boot: BootView,
  disk: DiskView,
  audit: AuditView,
  logs: LogView,
  'log-analysis': LogAnalysisView,
  startup: StartupView,
  'image-gen': ImageView,
  'video-gen': VideoView,
  gallery: GalleryView,
  memory: MemoryView,
  'ai-models': OllamaModelsView,
  snapshots: SnapshotView,
  history: HistoryView,
  scheduler: SchedulerView,
  automations: AutomationsView,
  cron: CronView,
  ssh: SshView,
  firewall: FirewallView,
  benchmark: BenchmarkView,
  vault: VaultView,
  env: EnvView,
  'app-launcher': AppLauncherView,
  health: HealthReportView,
  settings: SettingsPage,
  terminal: TerminalView
}

export default function App() {
  const { animationsEnabled } = useTheme()
  const [activeTab, setActiveTab] = useState('dashboard')
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(true)
  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false)
  const [isShortcutsOpen, setIsShortcutsOpen] = useState(false)
  const [i2vSource, setI2vSource] = useState<string | null>(null)
  const [stats, setStats] = useState<SystemStats | null>(null)
  const [sidebarWidth, setSidebarWidth] = useState(() => parseInt(localStorage.getItem('vortex-sidebar-width') ?? '256', 10))
  const [explorePkg, setExplorePkg] = useState<string | null>(null)
  const isDraggingRef = useRef(false)
  const dragStartXRef = useRef(0)
  const dragStartWidthRef = useRef(256)
  const alertCooldownRef = useRef<Record<string, number>>({ cpu: 0, ram: 0, gpu: 0 })

  const handleDragStart = useCallback((e: React.MouseEvent) => {
    if (!isSidebarExpanded) return
    e.preventDefault()
    isDraggingRef.current = true
    dragStartXRef.current = e.clientX
    dragStartWidthRef.current = sidebarWidth
    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'
  }, [isSidebarExpanded, sidebarWidth])

  useEffect(() => {
    const onMove = (e: MouseEvent) => {
      if (!isDraggingRef.current) return
      const delta = e.clientX - dragStartXRef.current
      const w = Math.max(180, Math.min(380, dragStartWidthRef.current + delta))
      const el = document.querySelector('.v-sidebar') as HTMLElement | null
      if (el) { el.style.width = `${w}px`; el.style.transition = 'none' }
    }
    const onUp = () => {
      if (!isDraggingRef.current) return
      isDraggingRef.current = false
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
      const el = document.querySelector('.v-sidebar') as HTMLElement | null
      if (el) {
        const w = parseInt(el.style.width, 10) || dragStartWidthRef.current
        el.style.transition = ''
        setSidebarWidth(w)
        localStorage.setItem('vortex-sidebar-width', String(w))
      }
    }
    window.addEventListener('mousemove', onMove)
    window.addEventListener('mouseup', onUp)
    return () => { window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onUp) }
  }, [])

  // Global keyboard shortcuts
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const tag = (e.target as HTMLElement)?.tagName
      const isTyping = tag === 'INPUT' || tag === 'TEXTAREA'

      if (e.ctrlKey && !e.shiftKey && !e.altKey) {
        const n = parseInt(e.key)
        if (n >= 1 && n <= navItems.length) {
          e.preventDefault()
          setActiveTab(navItems[n - 1].id)
          return
        }
        if (e.key === 'k' && !isTyping) {
          e.preventDefault()
          setActiveTab('assistant')
          setTimeout(() => window.dispatchEvent(new CustomEvent('vortex-focus-ai')), 50)
          return
        }
        if (e.key === '`' && !isTyping) {
          e.preventDefault()
          setActiveTab('terminal')
          setTimeout(() => window.dispatchEvent(new CustomEvent('vortex-focus-terminal')), 50)
          return
        }
        if (e.key === 'p') {
          e.preventDefault()
          setIsCommandPaletteOpen(true)
          return
        }
      }
      if (e.ctrlKey && e.shiftKey && e.key === 'N') {
        e.preventDefault()
        window.dispatchEvent(new CustomEvent('vortex-new-chat'))
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [])

  // Renderer-side context menu listener (aggresive restoration)
  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      e.preventDefault()
      if (window.electron) {
        // Build basic props to mimic Electron's native context-menu event
        const props = {
          x: e.clientX,
          y: e.clientY,
          editFlags: {
            canCut: true,
            canCopy: true,
            canPaste: true
          }
        }
        window.electron.showContextMenu(props)
      }
    }
    window.addEventListener('contextmenu', handleContextMenu)
    return () => window.removeEventListener('contextmenu', handleContextMenu)
  }, [])

  useEffect(() => {
    const COOLDOWN = 5 * 60 * 1000
    const checkAlerts = (s: SystemStats | null, gpuUsedPct: number) => {
      const now = Date.now()
      let thresholds: AlertThresholds = DEFAULT_THRESHOLDS
      try { thresholds = { ...DEFAULT_THRESHOLDS, ...JSON.parse(localStorage.getItem(ALERT_THRESHOLDS_KEY) ?? '{}') } } catch {}

      const metrics: { key: keyof AlertThresholds; value: number; label: string }[] = [
        { key: 'cpu', value: s?.cpu?.load ?? 0, label: 'CPU' },
        { key: 'ram', value: s?.memory ? (s.memory.used / s.memory.total) * 100 : 0, label: 'RAM' },
        { key: 'gpu', value: gpuUsedPct, label: 'GPU VRAM' },
      ]
      for (const { key, value, label } of metrics) {
        const limit = thresholds[key]
        if (limit === 0) continue
        if (value >= limit && now - (alertCooldownRef.current[key] ?? 0) > COOLDOWN) {
          alertCooldownRef.current[key] = now
          notify(`${label} Alert`, `${label} usage is ${Math.round(value)}% (threshold: ${limit}%)`, 'warning')
        }
      }
    }

    let lastGpuPct = 0
    const fetchStats = async () => {
      if (!window.electron) return
      try {
        const s = await window.electron.getSystemStats()
        setStats(s)
        try {
          const g = await window.electron.gpuVramStats()
          if (g?.success && g.total > 0) lastGpuPct = (g.used / g.total) * 100
        } catch {}
        checkAlerts(s, lastGpuPct)
      } catch (e) {
        console.error('Failed to fetch stats:', e)
      }
    }
    fetchStats()
    const id = setInterval(fetchStats, 2000)
    return () => clearInterval(id)
  }, [])

  useEffect(() => {
    const handleSetI2vSource = (e: Event) => {
      setI2vSource((e as CustomEvent<string>).detail)
    }
    window.addEventListener('vortex-set-i2v-source', handleSetI2vSource)
    return () => window.removeEventListener('vortex-set-i2v-source', handleSetI2vSource)
  }, [])

  const handleSetActiveTab = useCallback(async (id: string) => {
    const AI_TABS = new Set(['assistant', 'image-gen', 'video-gen'])
    const isAI = AI_TABS.has(activeTab)
    const targetAI = AI_TABS.has(id)
    const isAssistant = activeTab === 'assistant'
    const isComfy = activeTab === 'image-gen' || activeTab === 'video-gen'
    const targetAssistant = id === 'assistant'
    const targetComfy = id === 'image-gen' || id === 'video-gen'
    const el = window.electron

    // Entering an AI tab from a non-AI tab — boot Ollama service
    if (!isAI && targetAI) {
      console.log('[Vortex] Entering AI tab — starting Ollama service')
      el?.ollamaServiceStart?.()
    }

    // Leaving all AI tabs to a system tab — stop service to fully free VRAM
    if (isAI && !targetAI) {
      if (isAssistant) {
        console.log('[Vortex] Leaving AI — purging LLM then stopping Ollama service')
        await el?.ollamaPurge?.()
      }
      if (isComfy) {
        console.log('[Vortex] Leaving AI — purging ComfyUI VRAM')
        await el?.comfyPurge?.()
      }
      console.log('[Vortex] Stopping Ollama service')
      el?.ollamaServiceStop?.()
    }

    // Cross-engine swap: Assistant → Image/Video
    if (isAssistant && targetComfy) {
      console.log('[Vortex] Swapping LLM -> Comfy: purging LLM')
      await el?.ollamaPurge?.()
    }

    // Cross-engine swap: Image/Video → Assistant
    if (isComfy && targetAssistant) {
      console.log('[Vortex] Swapping Comfy -> LLM: purging Comfy')
      await el?.comfyPurge?.()
    }

    setActiveTab(id)
  }, [activeTab])

  const renderActiveView = () => {
    const Component = VIEW_MAP[activeTab] || (() => <div className="p-20 opacity-30 italic font-mono">View_Missing: {activeTab}</div>)

    // Inject special props for specific components
    const specialProps: Partial<ActiveViewProps> = {}
    if (activeTab === 'dashboard') specialProps.onNavigate = setActiveTab
    if (activeTab === 'packages') specialProps.onExplore = (name: string) => { setExplorePkg(name); setActiveTab('depgraph') }
    if (activeTab === 'depgraph') specialProps.initialPackage = explorePkg
    if (activeTab === 'image-gen') specialProps.onAnimate = (url: string) => { setI2vSource(url); setActiveTab('video-gen') }
    if (activeTab === 'video-gen') specialProps.i2vSource = i2vSource
    if (activeTab === 'terminal') specialProps.onAskAI = setActiveTab
    if (activeTab === 'dashboard' || activeTab === 'docker') specialProps.stats = stats

    return <Component {...(specialProps as ActiveViewProps)} />
  }

  return (
    <div className="v-app" style={{ border: '1px solid rgba(255,255,255,0.05)' }}>

      <Sidebar
        activeTab={activeTab}
        setActiveTab={handleSetActiveTab}
        isExpanded={isSidebarExpanded}
        setIsExpanded={setIsSidebarExpanded}
        cpuLoad={stats?.cpu?.load ?? 0}
        sidebarWidth={sidebarWidth}
      />
      {/* Drag handle */}
      {isSidebarExpanded && (
        <div
          onMouseDown={handleDragStart}
          style={{ width: '4px', flexShrink: 0, cursor: 'col-resize', background: 'transparent', position: 'relative', zIndex: 20, transition: 'background 0.15s' }}
          onMouseEnter={e => { (e.currentTarget as HTMLDivElement).style.background = 'rgba(239,68,68,0.25)' }}
          onMouseLeave={e => { if (!isDraggingRef.current) (e.currentTarget as HTMLDivElement).style.background = 'transparent' }}
        />
      )}

      <CommandPalette
        isOpen={isCommandPaletteOpen}
        setIsOpen={setIsCommandPaletteOpen}
        onNavigate={setActiveTab}
      />
      <ShortcutsOverlay isOpen={isShortcutsOpen} setIsOpen={setIsShortcutsOpen} />

      <main className="v-main">
        <Header stats={stats} />

        <div style={{ flex: 1, overflow: 'hidden', position: 'relative', background: 'var(--ink-900)' }}>
          {/* Subtle Grid Pattern */}
          <div style={{ 
            position: 'absolute', inset: 0, opacity: 0.03, pointerEvents: 'none',
            backgroundImage: 'radial-gradient(#ffffff 1px, transparent 1px)', backgroundSize: '32px 32px' 
          }} />

          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: animationsEnabled ? 0 : 1, x: animationsEnabled ? 20 : 0 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: animationsEnabled ? 0 : 1, x: animationsEnabled ? -20 : 0 }}
              transition={{ duration: animationsEnabled ? 0.3 : 0, ease: "easeOut" }}
              style={{ height: '100%', width: '100%', padding: '32px', overflowY: 'auto', position: 'relative', zIndex: 10, boxSizing: 'border-box' }}
            >
              <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
                <header style={{ marginBottom: '32px' }}>
                  <h1 className="v-h1">
                    {activeTab.charAt(0).toUpperCase() + activeTab.slice(1).replace('-', ' ')}
                    <span style={{ WebkitTextFillColor: 'var(--crimson)', opacity: 0.5, marginLeft: '10px', fontStyle: 'normal', fontWeight: 300 }}>/</span>
                  </h1>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginTop: '4px', fontFamily: 'monospace', fontSize: '10px', textTransform: 'uppercase', letterSpacing: '0.1em', color: '#334155' }}>
                    <span className="animate-pulse-dot" style={{ display: 'inline-block', width: '6px', height: '6px', borderRadius: '50%', background: 'var(--signal)', flexShrink: 0 }} />
                    <span>System Online</span>
                  </div>
                </header>

                {renderActiveView()}
              </div>
            </motion.div>
          </AnimatePresence>
        </div>
        <StatusBar stats={stats} />
      </main>
    </div>
  )
}

function DepGraphWrapper({ initialPackage }: { initialPackage: string | null }) {
  const [tree, setTree] = useState<PackageDepTree | null>(null)
  const [loading, setLoading] = useState(false)
  const [target, setTarget] = useState(initialPackage ?? 'linux')

  useEffect(() => {
    async function fetch() {
      if (!window.electron) return
      setLoading(true)
      const res = await window.electron.packageGetTree(target)
      setTree(res)
      setLoading(false)
    }
    fetch()
  }, [target])

  if (!tree && loading) return <div style={{ padding: '40px', textAlign: 'center', fontFamily: 'monospace', color: '#52525b' }}>Analysing dependency tree...</div>
  if (!tree) return <div style={{ padding: '40px', textAlign: 'center', fontFamily: 'monospace', color: '#52525b' }}>Failed to load dependency data.</div>

  return (
    <div style={{ padding: '24px' }}>
      <div style={{ marginBottom: '20px' }}>
        <h2 style={{ fontSize: '18px', fontWeight: 'bold', color: 'white', margin: 0 }}>Dependency Visualiser</h2>
        <p style={{ fontSize: '11px', color: '#52525b', marginTop: '4px' }}>Deep-scan of package relationships for <span style={{ color: 'var(--crimson)' }}>{target}</span></p>
      </div>
      <DepGraph tree={tree} loading={loading} onDrillDown={setTarget} />
    </div>
  )
}

import { useState, useRef, useEffect, useMemo, memo } from 'react'
import { createPortal } from 'react-dom'
import { useOllama, type Session } from '../hooks/useOllama'
import { notify } from '../lib/notifications'
import { motion, AnimatePresence } from 'framer-motion'
import { Send, Square, Bot, User, Loader2, AlertCircle, Activity, FolderOpen, RotateCcw, MessageSquare, Plus, Trash2, Check, X, Zap, Wrench, ChevronDown, ChevronRight, Terminal, Paperclip, Layers, Wand2, Copy, Network, Brain, Mic, MicOff, Volume2, VolumeX } from 'lucide-react'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'
import remarkMath from 'remark-math'
import rehypeKatex from 'rehype-katex'
import 'katex/dist/katex.min.css'
import ArtifactView from './ArtifactView'
import { useTheme } from './ThemeProvider'
import { consumeTerminalQuery } from '../lib/terminalBridge'

export default function AssistantView() {
  const { playSound } = useTheme()
  const {
    models,
    activeModel,
    setActiveModel,
    messages,
    sessions,
    currentSessionId,
    loadSession,
    createSession,
    renameSession,
    deleteSession,
    sendMessage,
    cancelStream,
    clearMessages,
    pullModel,
    pullProgress,
    isStreaming,
    error,
    smartRoute,
    setSmartRoute,
    lastRoutedModel,
    agentMode,
    setAgentMode,
    orchestraMode,
    setOrchestraMode,
    thinkMode,
    setThinkMode,
    tokenUsage,
  } = useOllama()

  const [showSessions, setShowSessions] = useState(false)
  const [editingSessionId, setEditingSessionId] = useState<number | null>(null)
  const [editingName, setEditingName] = useState('')
  const [showContextPicker, setShowContextPicker] = useState(false)
  const contextBtnRef = useRef<HTMLButtonElement | null>(null)
  const [contextPickerPos, setContextPickerPos] = useState({ top: 0, left: 0 })
  useEffect(() => {
    if (!showContextPicker || !contextBtnRef.current) return
    const reposition = () => {
      const r = contextBtnRef.current?.getBoundingClientRect()
      if (r) setContextPickerPos({ top: r.bottom + 6, left: r.left })
    }
    reposition()
    window.addEventListener('resize', reposition)
    window.addEventListener('scroll', reposition, true)
    return () => {
      window.removeEventListener('resize', reposition)
      window.removeEventListener('scroll', reposition, true)
    }
  }, [showContextPicker])

  const [input, setInput] = useState(() => localStorage.getItem('vortex-ai-input') || '')

  useEffect(() => {
    localStorage.setItem('vortex-ai-input', input)
  }, [input])

  // Pick up any pending query forwarded from the terminal via terminalBridge
  useEffect(() => {
    const q = consumeTerminalQuery()
    if (q) setInput(q)
  }, [])
  const [isDiagnosing, setIsDiagnosing] = useState(false)
  const [project, setProject] = useState<{ path: string, fileCount: number } | null>(null)
  const [isScanning, setIsScanning] = useState(false)
  const [showNodeManager, setShowNodeManager] = useState(false)
  const [contextFlags, setContextFlags] = useState<{ rag: boolean; terminal: boolean; memory: boolean }>(() => {
    const s = localStorage.getItem('vortex-context-flags')
    return s ? JSON.parse(s) : { rag: true, terminal: true, memory: true }
  })
  const [attachedFile, setAttachedFile] = useState<{ name: string; content: string; truncated?: boolean; type: 'text' | 'image' } | null>(null)
  const [isRecording, setIsRecording] = useState(false)
  const [isTranscribing, setIsTranscribing] = useState(false)
  const [ttsEnabled, setTtsEnabled] = useState(() => localStorage.getItem('vortex-tts') === 'true')
  useEffect(() => { localStorage.setItem('vortex-tts', String(ttsEnabled)) }, [ttsEnabled])
  const mediaRecorderRef = useRef<MediaRecorder | null>(null)
  const recordedChunksRef = useRef<Blob[]>([])

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
      const mime = MediaRecorder.isTypeSupported('audio/webm;codecs=opus') ? 'audio/webm;codecs=opus' : 'audio/webm'
      const rec = new MediaRecorder(stream, { mimeType: mime })
      mediaRecorderRef.current = rec
      recordedChunksRef.current = []
      rec.ondataavailable = e => { if (e.data.size > 0) recordedChunksRef.current.push(e.data) }
      rec.onstop = async () => {
        stream.getTracks().forEach(t => t.stop())
        const blob = new Blob(recordedChunksRef.current, { type: mime })
        const arr = await blob.arrayBuffer()
        const b64 = btoa(String.fromCharCode(...new Uint8Array(arr)))
        setIsTranscribing(true)
        try {
          const res = await (window as any).electron?.voiceTranscribe?.({ audioBase64: b64, mimeType: mime })
          if (res?.success && res.text) setInput(prev => (prev ? prev + ' ' : '') + res.text)
          else notify('Transcription failed', res?.error || 'Whisper not available', 'error')
        } finally { setIsTranscribing(false) }
      }
      rec.start()
      setIsRecording(true)
    } catch (e: any) {
      notify('Microphone unavailable', e.message || 'Could not access microphone', 'error')
    }
  }

  const stopRecording = () => {
    mediaRecorderRef.current?.stop()
    setIsRecording(false)
  }

  // Auto-TTS: when streaming ends, speak the last assistant message via Piper.
  const lastSpokenRef = useRef<string>('')
  const wasStreamingRef = useRef(false)
  const currentAudioRef = useRef<HTMLAudioElement | null>(null)
  const [isSpeaking, setIsSpeaking] = useState(false)
  const stopSpeech = () => {
    const a = currentAudioRef.current
    if (a) { try { a.pause(); a.currentTime = 0 } catch {} }
    currentAudioRef.current = null
    setIsSpeaking(false)
  }
  useEffect(() => {
    if (wasStreamingRef.current && !isStreaming && ttsEnabled) {
      const last = [...messages].reverse().find(m => m.role === 'assistant' && m.content)
      if (last && last.content !== lastSpokenRef.current) {
        lastSpokenRef.current = last.content
        // Strip code blocks, markdown, and <think> reasoning — TTS only needs prose.
        const clean = last.content
          .replace(/<think>[\s\S]*?<\/think>/g, '')
          .replace(/```[\s\S]*?```/g, '')
          .replace(/`[^`]*`/g, '')
          .replace(/[*_#>]/g, '')
          .trim()
          .slice(0, 800)
        if (clean) {
          ;(window as any).electron?.voiceSpeak?.({ text: clean }).then((res: any) => {
            if (res?.success && res.audioBase64) {
              try {
                stopSpeech() // interrupt any previous playback first
                const audio = new Audio(`data:audio/wav;base64,${res.audioBase64}`)
                currentAudioRef.current = audio
                audio.onended = () => { currentAudioRef.current = null; setIsSpeaking(false) }
                audio.onerror = () => { currentAudioRef.current = null; setIsSpeaking(false) }
                setIsSpeaking(true)
                audio.play().catch(() => { setIsSpeaking(false) })
              } catch { setIsSpeaking(false) }
            }
          }).catch(() => {})
        }
      }
    }
    wasStreamingRef.current = isStreaming
  }, [isStreaming, ttsEnabled, messages])

  const toggleFlag = (key: 'rag' | 'terminal' | 'memory') => {
    setContextFlags(prev => {
      const next = { ...prev, [key]: !prev[key] }
      localStorage.setItem('vortex-context-flags', JSON.stringify(next))
      return next
    })
  }

  const scrollRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLTextAreaElement>(null)

  useEffect(() => {
    const focus = () => {
      const q = consumeTerminalQuery()
      if (q) setInput(q)
      inputRef.current?.focus()
    }
    const newChat = () => clearMessages()
    window.addEventListener('vortex-focus-ai', focus)
    window.addEventListener('vortex-new-chat', newChat)
    return () => {
      window.removeEventListener('vortex-focus-ai', focus)
      window.removeEventListener('vortex-new-chat', newChat)
    }
  }, [clearMessages])

  useEffect(() => {
    async function checkProject() {
      const status = await (window as any).electron.ragStatus()
      if (status.path) setProject(status)
    }
    checkProject()
  }, [])

  // Auto-scroll to bottom when new tokens arrive
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight
    }
  }, [messages])

  const handleSelectProject = async () => {
    setIsScanning(true)
    try {
      const res = await (window as any).electron.ragSelectProject()
      if (res) setProject(res)
    } finally {
      setIsScanning(false)
    }
  }

  const buildPrompt = async (text: string, isImage: boolean) => {
    let finalPrompt = text
    const isGreeting = text.trim().length < 15

    if (attachedFile && !isImage) {
      finalPrompt = `Attached file — \`${attachedFile.name}\`${attachedFile.truncated ? ' (truncated to 20k chars)' : ''}:\n\`\`\`\n${attachedFile.content}\n\`\`\`\n\n${finalPrompt}`
    }

    // Only inject heavy system context if the user is asking a real question (not just saying hi)
    if (!isGreeting) {
      if (contextFlags.memory) {
        const memories = await (window as any).electron.memoryGetAll()
        if (memories && memories.length > 0) {
          const facts = memories.map((m: any) => `- ${m.fact}`).join('\n')
          finalPrompt = `Persistent Memory (Learned Facts):\n${facts}\n\n${finalPrompt}`
        }
      }

      if (project && contextFlags.rag) {
        const context = await (window as any).electron.ragGetContext(text)
        if (context) finalPrompt = `${context}\n\nUser Question: ${finalPrompt}`
      }

      if (contextFlags.terminal) {
        const termBuffer: string = await (window as any).electron.ptyGetBuffer?.() ?? ''
        if (termBuffer.trim().length > 80) {
          finalPrompt = `Recent terminal output:\n\`\`\`\n${termBuffer.slice(-2000)}\n\`\`\`\n\n${finalPrompt}`
        }
      }
    }

    return finalPrompt
  }

  const handleSend = async () => {
    if ((!input.trim() && !attachedFile) || isStreaming) return
    playSound('click')

    let images: string[] | undefined = undefined
    let finalInput = input

    if (attachedFile?.type === 'image') {
      images = [attachedFile.content.split(',')[1]]
      if (!finalInput.trim()) finalInput = "Describe this image."
    }

    const prompt = await buildPrompt(finalInput, !!images)
    sendMessage(prompt, images)

    setInput('')
    setAttachedFile(null)
  }

  const handleQuickSend = async (text: string) => {
    if (isStreaming) return
    playSound('click')
    sendMessage(await buildPrompt(text, false))
  }

  const handleAttachFile = async () => {
    const result = await (window as any).electron.dialogOpenFile()
    if (!result || 'error' in result) return

    const ext = result.name.split('.').pop()?.toLowerCase()
    const isImage = ['png', 'jpg', 'jpeg', 'webp', 'gif'].includes(ext || '')

    if (isImage) {
      const base64 = await (window as any).electron.systemReadLocalImage(result.path)
      if (base64 && !base64.error) {
        setAttachedFile({ name: result.name, content: base64, type: 'image' })
      }
    } else {
      setAttachedFile({ name: result.name, content: result.content, truncated: result.truncated, type: 'text' })
    }
    playSound('click')
  }

  const handleDiagnose = async () => {
    if (isStreaming || isDiagnosing) return
    setIsDiagnosing(true)
    try {
      const logs = await (window as any).electron.systemGetErrorLogs(20)
      const prompt = `I am experiencing some system issues. Here are the last 20 critical entries from my journalctl logs:\n\n\`\`\`\n${logs}\n\`\`\`\n\nPlease analyze these logs, explain what might be going wrong, and suggest a fix.`
      sendMessage(prompt)
    } catch (e) {
      console.error('Diagnosis failed:', e)
    } finally {
      setIsDiagnosing(false)
    }
  }

  const startRename = (s: Session) => {
    setEditingSessionId(s.id)
    setEditingName(s.name)
  }
  const commitRename = async () => {
