interface SidebarProps {
  activeTab: string
  setActiveTab: (id: string) => void
  isExpanded: boolean
  setIsExpanded: (expanded: boolean) => void
  cpuLoad: number
  sidebarWidth: number
}

export default function Sidebar({ activeTab, setActiveTab, isExpanded, setIsExpanded, cpuLoad, sidebarWidth }: SidebarProps) {
  const { theme, setTheme, playSound } = useTheme()

  const handleTabClick = (id: string) => {
    playSound('click')
    setActiveTab(id)
  }

  return (
    <aside
      className="v-sidebar"
      style={{ width: isExpanded ? sidebarWidth : 64 }}
    >
      <div className="h-14 flex items-center px-4 border-b border-white/5 drag">
        <div className="w-8 h-8 rounded-lg bg-crimson flex items-center justify-center mr-3 flex-shrink-0 crimson-glow shadow-[0_0_10px_rgba(239,68,68,0.3)]">
          <span className="font-bold text-white text-xs">V2</span>
        </div>
        {isExpanded && (
          <span className="font-bold tracking-widest text-[10px] uppercase truncate">
            Vortex <span className="text-zinc-500">//</span> Agentic
          </span>
        )}
      </div>

      <nav className="flex-1 py-4 overflow-y-auto no-drag space-y-6">
        {navCategories.map((cat) => (
          <div key={cat.label} className="space-y-1">
            {isExpanded && (
              <div className="px-6 py-2 flex items-center gap-3">
                <span className="text-[9px] font-black text-zinc-500 uppercase tracking-[0.25em] whitespace-nowrap">{cat.label}</span>
                <div className="h-[1px] flex-1 bg-white/5" />
              </div>
            )}
            <div className="space-y-0.5">
              {cat.items.map((item) => (
                <button
                  key={item.id}
                  onClick={() => handleTabClick(item.id)}
                  onMouseEnter={() => playSound('hover')}
                  onDragOver={(e) => {
                    if (item.id === 'video-gen') {
                      e.preventDefault()
                      e.dataTransfer.dropEffect = 'copy'
                      const timer = window._dragTimer
                      if (!timer && activeTab !== 'video-gen') {
                        window._dragTimer = setTimeout(() => {
                          setActiveTab('video-gen')
                          playSound('hover')
                        }, 600)
                      }
                    }
                  }}
                  onDragLeave={() => {
                    if (item.id === 'video-gen') {
                      if (window._dragTimer) {
                        clearTimeout(window._dragTimer)
                        delete window._dragTimer
                      }
                    }
                  }}
                  onDrop={(e) => {
                    if (item.id === 'video-gen') {
                      e.preventDefault()
                      if (window._dragTimer) {
                        clearTimeout(window._dragTimer)
                        delete window._dragTimer
                      }
                      const url = e.dataTransfer.getData('text/plain')
                      if (url && url.startsWith('http')) {
                        window.dispatchEvent(new CustomEvent('vortex-set-i2v-source', { detail: url }))
                        setActiveTab('video-gen')
                        playSound('success')
                      } else if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
                        const file = e.dataTransfer.files[0]
                        if (file.type.startsWith('image/')) {
                          const localUrl = URL.createObjectURL(file)
                          window.dispatchEvent(new CustomEvent('vortex-set-i2v-source', { detail: localUrl }))
                          setActiveTab('video-gen')
                          playSound('success')
                        }
                      }
                    }
                  }}
                  className={cn(
                    "v-nav-item",
                    activeTab === item.id && "active"
                  )}
                >
                  <div style={{ position: 'relative', flexShrink: 0 }}>
                    <item.icon className={cn(
                      "w-3.5 h-3.5 transition-transform",
                      activeTab === item.id ? "crimson-glow text-crimson" : "text-zinc-500"
                    )} />
                    {!isExpanded && item.id === 'dashboard' && (
                      <div style={{
                        position: 'absolute', top: '-3px', right: '-4px',
                        width: '6px', height: '6px', borderRadius: '50%',
                        background: cpuLoad > 85 ? 'var(--crimson)' : cpuLoad > 60 ? '#f59e0b' : 'var(--signal)',
                        boxShadow: `0 0 5px ${cpuLoad > 85 ? 'var(--crimson)' : cpuLoad > 60 ? '#f59e0b' : 'var(--signal)'}`,
                      }} />
                    )}
                  </div>
                  {isExpanded && (
                    <span className="ml-4 truncate text-[11px] font-medium normal-case tracking-normal">{item.label}</span>
                  )}
                  {activeTab === item.id && (
                    <motion.div 
                      layoutId="active-nav"
                      className="absolute left-0 w-[2px] h-4 bg-crimson rounded-r-full"
                    />
                  )}
                </button>
              ))}
            </div>
          </div>
        ))}
      </nav>

      <div className="p-4 border-t border-white/5 no-drag bg-black/20 space-y-3">
        {isExpanded && (
          <div className="flex items-center justify-between px-2 mb-2">
            <Palette size={12} className="text-zinc-500" />
            <div className="flex gap-1.5">
              {(['vortex-red', 'cyber-blue', 'neon-gold', 'matrix-green'] as const).map((t) => (
                <button
                  key={t}
                  onClick={() => { setTheme(t); playSound('success'); }}
                  className={cn(
                    "w-3 h-3 rounded-full border border-white/10 transition-transform hover:scale-125",
                    t === 'vortex-red' && "bg-red-500",
                    t === 'cyber-blue' && "bg-cyan-400",
                    t === 'neon-gold' && "bg-amber-500",
                    t === 'matrix-green' && "bg-emerald-500",
                    theme.name === t && "ring-2 ring-white/20 ring-offset-2 ring-offset-ink-800"
                  )}
                />
              ))}
            </div>
          </div>
        )}
        <button 
          onClick={() => { setIsExpanded(!isExpanded); playSound('click'); }}
          className="w-full h-8 flex items-center justify-center rounded-lg hover:bg-white/5 transition-colors text-zinc-600 hover:text-zinc-300"
        >
          <span className="text-[9px] font-bold uppercase tracking-[0.2em]">
            {isExpanded ? "« Collapse" : "»"}
          </span>
        </button>
      </div>
    </aside>
  )
}

import { useState, useEffect } from 'react'
import { Cpu, MemoryStick, Bot, Shield, Zap, MessageSquare, Hash } from 'lucide-react'

interface StatusBarProps {
  stats: {
    cpu?: {
      load: number
    }
    memory?: {
      used: number
      total: number
    }
  } | null
}

function statColor(pct: number) {
  if (pct > 85) return 'var(--crimson)'
  if (pct > 60) return '#f59e0b'
  return 'var(--signal)'
}

function Pill({ icon: Icon, label, value, color }: { icon: React.ComponentType<{ size?: number; style?: React.CSSProperties }>; label: string; value: string; color: string }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
      <Icon size={9} style={{ color, flexShrink: 0 }} />
      <span style={{ color: '#3f3f46' }}>{label}</span>
      <span style={{ color, fontWeight: 'bold' }}>{value}</span>
    </div>
  )
}

function Sep() {
  return <div style={{ width: '1px', height: '10px', background: 'rgba(255,255,255,0.06)' }} />
}

const PROFILES = ['performance', 'balanced', 'power-saver'] as const
const PROFILE_COLOR: Record<string, string> = {
  performance: 'var(--crimson)',
  balanced:    '#f59e0b',
  'power-saver': 'var(--signal)',
}

export default function StatusBar({ stats }: StatusBarProps) {
  const cpuPct = stats?.cpu?.load ?? null
  const ramPct = stats?.memory ? (stats.memory.used / stats.memory.total) * 100 : null
  const [model, setModel] = useState(() => (localStorage.getItem('vortex-default-model') ?? '').split(':')[0] || 'no model')
  const [sessionName, setSessionName] = useState('New Chat')
  const [powerProfile, setPowerProfile] = useState<string | null>(null)
  const [tokenUsage, setTokenUsage] = useState<{ promptTokens: number; completionTokens: number } | null>(null)

  useEffect(() => {
    const handleSessionChange = (e: Event) => {
      const detail = (e as CustomEvent).detail
      setSessionName(detail?.name || 'New Chat')
    }
    const handleModelChange = (e: Event) => {
      const detail = (e as CustomEvent).detail
      setModel((String(detail) ?? '').split(':')[0] || 'no model')
    }
    const handleTokenUsage = (e: Event) => {
      const detail = (e as CustomEvent).detail as { promptTokens: number; completionTokens: number } | null
      setTokenUsage(detail)
    }
    window.addEventListener('vortex-session-change', handleSessionChange)
    window.addEventListener('vortex-model-change', handleModelChange)
    window.addEventListener('vortex-token-usage', handleTokenUsage)
    return () => {
      window.removeEventListener('vortex-session-change', handleSessionChange)
      window.removeEventListener('vortex-model-change', handleModelChange)
      window.removeEventListener('vortex-token-usage', handleTokenUsage)
    }
  }, [])

  useEffect(() => {
    const el = window.electron
    if (!el?.powerGetProfile) return
    el.powerGetProfile().then((r) => { if (r.profile) setPowerProfile(r.profile) })
  }, [])

  const cycleProfile = async () => {
    if (!powerProfile) return
    const idx = PROFILES.indexOf(powerProfile as typeof PROFILES[number])
    const next = PROFILES[(idx + 1) % PROFILES.length]
    const r = await window.electron?.powerSetProfile(next)
    if (r?.success) setPowerProfile(next)
  }

  return (
    <div style={{
      height: '26px',
      display: 'flex',
      alignItems: 'center',
      padding: '0 16px',
      gap: '14px',
      background: 'rgba(4,7,15,0.95)',
      borderTop: '1px solid rgba(255,255,255,0.04)',
      fontSize: '9px',
      fontFamily: 'monospace',
      textTransform: 'uppercase',
      letterSpacing: '0.08em',
      flexShrink: 0,
      userSelect: 'none',
    }}>
      <Pill
        icon={Cpu}
        label="CPU"
        value={cpuPct !== null ? `${cpuPct.toFixed(1)}%` : '--.-%'}
        color={cpuPct !== null ? statColor(cpuPct) : '#3f3f46'}
      />
      <Sep />
      <Pill
        icon={MemoryStick}
        label="RAM"
        value={ramPct !== null ? `${ramPct.toFixed(1)}%` : '--.-%'}
        color={ramPct !== null ? statColor(ramPct) : '#3f3f46'}
      />
      <Sep />
      <Pill icon={Bot} label="Model" value={model} color="#52525b" />
      {tokenUsage && (
        <>
          <Sep />
          <Pill icon={Hash} label="Ctx" value={`${(tokenUsage.promptTokens / 1000).toFixed(1)}k`} color="#52525b" />
        </>
      )}
      <Sep />
      <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
        <MessageSquare size={9} style={{ color: '#52525b', flexShrink: 0 }} />
        <span style={{ color: '#3f3f46' }}>Session</span>
        <span style={{ color: '#52525b', fontWeight: 'bold' }}>{sessionName}</span>
      </div>

      {powerProfile && (
        <>
          <Sep />
          <button
            onClick={cycleProfile}
            title="Click to cycle power profile"
            style={{
              display: 'flex', alignItems: 'center', gap: '5px', background: 'none', border: 'none',
              cursor: 'pointer', padding: 0, fontFamily: 'monospace', fontSize: '9px',
              textTransform: 'uppercase', letterSpacing: '0.08em',
            }}
          >
            <Zap size={9} style={{ color: PROFILE_COLOR[powerProfile] ?? '#52525b' }} />
            <span style={{ color: PROFILE_COLOR[powerProfile] ?? '#52525b' }}>{powerProfile}</span>
          </button>
        </>
      )}

      <div style={{ flex: 1 }} />

      <div style={{ display: 'flex', alignItems: 'center', gap: '5px', color: '#27272a' }}>
        <Shield size={8} />
        <span>All AI Local</span>
      </div>
    </div>
  )
}
